import React, { useState, useEffect, useMemo } from 'react';
import Select from 'react-select';
import './EditPurchase.css';

const EditPurchase = ({ purchase, handleUpdate, locations, vendors }) => {
  const [updatedPurchase, setUpdatedPurchase] = useState({ ...purchase });
  const [showExtras, setShowExtras] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [responseChanges, responseList] = await Promise.all([
          fetch(`http://localhost:8081/materialchangesAPI/${updatedPurchase.materialid}`),
          fetch(`http://localhost:8081/materiallist/${updatedPurchase.materialid}`),
        ]);

        const [dataChanges, dataList] = await Promise.all([
          responseChanges.json(),
          responseList.json(),
        ]);

        console.log('Data changes fetched:', dataChanges);
        console.log('Data list fetched:', dataList);

        // Check if extras=1 in the materiallist data
        if (dataList && dataList.extras === 1) {
          console.log('Showing extras...');
          setShowExtras(true);
        } else {
          console.log('Hiding extras...');
          setShowExtras(false);
        }
      } catch (error) {
        console.error('Error fetching material data:', error);
      }
    };

    fetchData(); // Call the fetchData function

  }, [updatedPurchase.materialid]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUpdatedPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleUpdate(updatedPurchase);
  };

  const handleVendorChange = (selectedOption) => {
    const selectedVendor = vendors.find((vendor) => vendor.name === selectedOption?.label);
    setUpdatedPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
      vendorname: selectedOption ? selectedOption.label : '',
    }));
  };

  const vendorOptions = useMemo(
    () => vendors.map((vendor) => ({ value: vendor.name, label: vendor.name })),
    [vendors]
  );

  return (
    <form onSubmit={handleSubmit} className='edit-purchase-form'>
      <div>
        <label>Location:</label>
        <select name="location" value={updatedPurchase.location} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={updatedPurchase.materialid} onChange={handleChange} required />
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={updatedPurchase.materialname} readOnly required />
      </div>
      {showExtras && (
        <div>
          <label>Width:</label>
          <input
            type="text"
            name="width"
            value={updatedPurchase.width}
            onChange={handleChange}
            required
          />
        </div>
      )}
      {showExtras && (
        <div>
          <label>LOT#:</label>
          <input
            type="text"
            name="lotnumber"
            value={updatedPurchase.lotnumber}
            onChange={handleChange}
            required
          />
        </div>
      )}
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={updatedPurchase.quantity} onChange={handleChange} required />
      </div>
      <div>
        <label>Price:</label>
        <input type="text" name="price" value={updatedPurchase.price} onChange={handleChange} required />
      </div>
      <div>
        <label>Vendor:</label>
        <Select
          options={vendorOptions}
          value={
            updatedPurchase.vendorname
              ? { value: updatedPurchase.vendorname, label: updatedPurchase.vendorname }
              : null
          }
          onChange={handleVendorChange}
          placeholder="Select a Vendor"
          isSearchable
          required
        />
      </div>
      <button type="submit" className="edit-purchase-btn">Edit Purchase</button>
    </form>
  );
};

export default EditPurchase;
